#include <stdio.h>
#include <string.h>

int main() {
    char s[4000001];
    while (1) {
        if (fgets(s, sizeof(s), stdin) == NULL) break;
        s[strcspn(s, "\n")] = 0;
        if (strcmp(s, "End") == 0) break;
        int n = strlen(s);
        for (int i = 0; i < n; i++) {
            int max = 0;
            for (int j = 1; j <= i + 1; j++) {
                if (strncmp(s, s + n - j, j) == 0 && j < n) {
                    max = j;
                }
            }
            printf("%d", max);
            if (i < n - 1) printf(" ");
        }
        printf("\n");
    }
    return 0;
}

code.C++:
#include <iostream>
#include <string>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(NULL);
    string s;
    while (getline(cin, s)) {
        if (s == "End") break;
        int n = s.length();
        for (int i = 0; i < n; i++) {
            int max = 0;
            for (int j = 1; j <= i + 1; j++) {
                if (s.substr(0, j) == s.substr(n - j, j) && j < n) {
                    max = j;
                }
            }
            cout << max;
            if (i < n - 1) cout << " ";
        }
        cout << endl;
    }
    return 0;
}

code.Java:
import java.util.Scanner;
public class Main {
    public static void main(String[] args) {
        Scanner sc = new Scanner(System.in);
        while (sc.hasNextLine()) {
            String s = sc.nextLine();
            if (s.equals("End")) break;
            int n = s.length();
            for (int i = 0; i < n; i++) {
                int max = 0;
                for (int j = 1; j <= i + 1; j++) {
                    if (s.substring(0, j).equals(s.substring(n - j, n)) && j < n) {
                        max = j;
                    }
                }
                System.out.print(max);
                if (i < n - 1) System.out.print(" ");
            }
            System.out.println();
        }
    }
}

